WHERE ( sc_mem_m_chang_request.membership_no = sc_mem_m_chg_share_det.membership_no ) and ( sc_mem_m_chang_request.document_no = sc_mem_m_chg_share_det.document_no ) and ( sc_mem_m_chang_request.approve_status = '1'  ) 


